using namespace std;

class Solution {
public:
    int countLargestGroup(int n) {
        vector<int> counts(37, 0);
        for (int i = 1; i <= n; ++i) {
            int num = i;
            int sum = 0;
            while (num > 0) {
                sum += num % 10;
                num /= 10;
            }
            counts[sum]++;
        }
        int max_count = 0;
        for (int i = 1; i <= 36; ++i) {
            if (counts[i] > max_count) {
                max_count = counts[i];
            }
        }
        int result = 0;
        for (int i = 1; i <= 36; ++i) {
            if (counts[i] == max_count) {
                result++;
            }
        }
        return result;
    }
};

